package sn.gestionimmobiliere.backend.identity.application;
import java.io.IOException;import java.util.*;import org.springframework.http.HttpHeaders;import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;import org.springframework.security.core.authority.SimpleGrantedAuthority;import org.springframework.security.core.context.SecurityContextHolder;import org.springframework.stereotype.Component;import org.springframework.web.filter.OncePerRequestFilter;import io.jsonwebtoken.Claims;import jakarta.servlet.*;import jakarta.servlet.http.*;
@Component public class JwtAuthenticationFilter extends OncePerRequestFilter{private final JwtService jwt;public JwtAuthenticationFilter(JwtService j){jwt=j;}@Override protected void doFilterInternal(HttpServletRequest req,HttpServletResponse res,FilterChain chain)throws ServletException,IOException{String h=req.getHeader(HttpHeaders.AUTHORIZATION);try{if(h!=null&&h.startsWith("Bearer ")){Claims c=jwt.parse(h.substring(7));UUID org=UUID.fromString(c.get("organization_id",String.class));TenantContext.set(org);var auth=new UsernamePasswordAuthenticationToken(c.getSubject(),null,List.of(new SimpleGrantedAuthority("ROLE_"+c.get("role",String.class))));SecurityContextHolder.getContext().setAuthentication(auth);}chain.doFilter(req,res);}finally{TenantContext.clear();}}}
